+    let output = Command::new("bash")
+        .arg(CAPTURE_BASELINE_SCRIPT_PATH)
+        .arg("--diagnose-env")
+        .arg(format!("ci={}", baseline_ci.display()))
+        .arg("--diagnose-env")
